CREATE TABLE IF NOT EXISTS "seaql_migrations" ( "version" varchar NOT NULL PRIMARY KEY, "applied_at" bigint NOT NULL );
CREATE TABLE IF NOT EXISTS "people" ( "id" varchar NOT NULL PRIMARY KEY, "name" varchar NOT NULL, "birthdate" date_text NOT NULL, "dietary_goals" varchar, "dislikes" text NOT NULL, "favorites" text NOT NULL, "notes" varchar, "is_active" boolean NOT NULL DEFAULT TRUE, "created_at" timestamp_with_timezone_text NOT NULL, "updated_at" timestamp_with_timezone_text NOT NULL , "drink_preferences" text NULL, "drink_dislikes" text NULL);
CREATE TABLE IF NOT EXISTS "recipes" ( "id" varchar NOT NULL PRIMARY KEY, "slug" text NOT NULL, "name" varchar NOT NULL, "description" varchar, "source" varchar NOT NULL, "parent_recipe_id" varchar, "prep_time" text, "cook_time" text, "total_time" text, "servings" integer NOT NULL, "portion_size" text, "instructions" text NOT NULL, "ingredients" text NOT NULL, "nutrition_per_serving" text, "tags" text NOT NULL, "notes" varchar, "icon" varchar, "is_favorite" boolean NOT NULL DEFAULT FALSE, "times_made" integer NOT NULL DEFAULT 0, "last_made" timestamp_with_timezone_text, "created_at" timestamp_with_timezone_text NOT NULL, "updated_at" timestamp_with_timezone_text NOT NULL , "rating" double NULL, "source_url" text NULL);
CREATE UNIQUE INDEX "idx_recipes_slug" ON "recipes" ("slug");
CREATE TABLE IF NOT EXISTS "meals" ( "id" varchar NOT NULL PRIMARY KEY, "date" date_text NOT NULL, "meal_type" varchar NOT NULL, "order_index" integer NOT NULL, "servings" text NOT NULL, "created_at" timestamp_with_timezone_text NOT NULL, "updated_at" timestamp_with_timezone_text NOT NULL );
CREATE TABLE IF NOT EXISTS "meal_templates" ( "id" varchar NOT NULL PRIMARY KEY, "name" varchar NOT NULL, "meal_type" varchar NOT NULL, "servings" text NOT NULL, "created_at" timestamp_with_timezone_text NOT NULL, "updated_at" timestamp_with_timezone_text NOT NULL );
CREATE TABLE IF NOT EXISTS "settings" ( "key" varchar NOT NULL PRIMARY KEY, "value" text NOT NULL );
CREATE TABLE IF NOT EXISTS "bar_items" ( "id" varchar NOT NULL PRIMARY KEY, "name" varchar NOT NULL, "category" varchar NOT NULL, "created_at" timestamp_with_timezone_text NOT NULL );
CREATE TABLE IF NOT EXISTS "drink_recipes" ( "id" varchar NOT NULL PRIMARY KEY, "slug" text NOT NULL, "name" varchar NOT NULL, "description" varchar, "source" varchar NOT NULL, "servings" integer NOT NULL DEFAULT 1, "instructions" text NOT NULL, "ingredients" text NOT NULL, "technique" varchar, "glassware" varchar, "garnish" varchar, "tags" text NOT NULL, "notes" varchar, "icon" varchar, "is_favorite" boolean NOT NULL DEFAULT FALSE, "is_non_alcoholic" boolean NOT NULL DEFAULT FALSE, "rating" double NULL, "times_made" integer NOT NULL DEFAULT 0, "created_at" timestamp_with_timezone_text NOT NULL, "updated_at" timestamp_with_timezone_text NOT NULL , "source_url" text NULL);
CREATE UNIQUE INDEX "idx_drink_recipes_slug" ON "drink_recipes" ("slug");
